SELECT COUNT(DISTINCT C.SIAPE) AS QUANTIDADE FROM CALC_HORA_AULA_MEDIA C JOIN SERVIDOR S ON C.SIAPE = S.PK_SIAPE WHERE C.ANO = 2021 AND C.SEMESTRE = 1 AND C.SIGLA_CAMPUS = 'LUZ' AND (LOWER(COALESCE(C.AREA_INGRESSO,'')) LIKE LOWER('%EDUCACAO FISICA%') OR LOWER(COALESCE(C.AREA_INGRESSO,'')) LIKE LOWER('%EDUCACAO FISICA%')) AND LOWER(COALESCE(S.CONTRATO,'')) = LOWER('EFETIVOS')